-- db/seed_p4_ufe.sql
-- Makes 'uterine-fibroid-embolization' satisfy v_game_ready: MODELED vessel map + MODELED
-- generator (labeled; real guardrails) + taxonomy-keyed outcomes case_steps + UFE kit.
-- Reuses the 6 existing CITED UFE complications. Idempotent; data_version auto-bumps.

insert into public.vessel_maps (id, name, region, graph, notes) values
 ('femoral-to-uterine', 'Right CFA → contralateral uterine artery', 'Pelvic arterial (femoral to uterine)',
  $vm${"nodes": [{"id": "cfa_access", "name": "Right common femoral a. (access)", "diameter_mm": 8, "tortuosity": 2, "fragility": 3, "depth": "shallow"}, {"id": "eia", "name": "Right external iliac a.", "diameter_mm": 7, "tortuosity": 2, "fragility": 3, "depth": "mid"}, {"id": "cia", "name": "Right common iliac a.", "diameter_mm": 9, "tortuosity": 2, "fragility": 3, "depth": "mid"}, {"id": "aortic_bifurc", "name": "Aortic bifurcation", "diameter_mm": 18, "tortuosity": 1, "fragility": 3, "depth": "deep"}, {"id": "contra_iia", "name": "Left internal iliac a. (anterior division)", "diameter_mm": 6, "tortuosity": 4, "fragility": 4, "depth": "deep"}, {"id": "uterine_origin", "name": "Left uterine a. origin", "diameter_mm": 3, "tortuosity": 6, "fragility": 5, "depth": "deep"}, {"id": "uterine_target", "name": "Left uterine a. (target, distal)", "diameter_mm": 2.5, "tortuosity": 7, "fragility": 6, "depth": "deep"}], "edges": [{"from": "cfa_access", "to": "eia"}, {"from": "eia", "to": "cia"}, {"from": "cia", "to": "aortic_bifurc"}, {"from": "aortic_bifurc", "to": "contra_iia"}, {"from": "contra_iia", "to": "uterine_origin"}, {"from": "uterine_origin", "to": "uterine_target"}]}$vm$::jsonb, $vn$"Contralateral up-and-over femoral route to the uterine artery (unilateral access, bilateral treatment). diameter_mm = approximate adult reference anatomy (not patient-specific). tortuosity & fragility are MODELED 1-10 simulation parameters: uterine tortuosity 7 / fragility 6 encode catheter-induced spasm and nontarget-embolization risk."$vn$::text)
on conflict (id) do update set graph = excluded.graph, notes = excluded.notes, name = excluded.name, region = excluded.region;

delete from public.patient_generators where procedure_id = 'uterine-fibroid-embolization';
insert into public.patient_generators (procedure_id, source_paper_id, name, variables, guardrails, status) values
 ('uterine-fibroid-embolization', null, $gn$"premenopausal fibroid patient (MODELED \u2014 NOT a real cohort Table 1)"$gn$::text, $gv$[{"name": "age", "kind": "normal", "mean": 43, "sd": 6, "min": 25, "max": 54, "unit": "years", "data_class": "MODELED", "basis": "Premenopausal symptomatic-fibroid population; replace with a cited cohort Table 1."}, {"name": "sex_female", "kind": "bernoulli", "p": 1.0, "data_class": "MODELED", "basis": "UFE population is female by definition."}, {"name": "presentation", "kind": "categorical", "categories": [{"value": "menorrhagia", "p": 0.6}, {"value": "bulk symptoms", "p": 0.3}, {"value": "menorrhagia + bulk", "p": 0.1}], "data_class": "MODELED", "basis": "Modeled symptom mix; drives the EMR indication."}, {"name": "weight_kg", "kind": "normal", "mean": 76, "sd": 17, "min": 45, "max": 150, "unit": "kg", "data_class": "MODELED", "basis": "Feeds Cigarroa V_max = 5*kg/SCr contrast limit."}, {"name": "creatinine", "kind": "normal", "mean": 0.8, "sd": 0.2, "min": 0.5, "max": 2.5, "unit": "mg/dL", "data_class": "MODELED", "basis": "Drives eGFR (CKD-EPI 2021) and iodinated-contrast budget."}, {"name": "platelets", "kind": "normal", "mean": 260, "sd": 60, "min": 90, "max": 450, "unit": "x10^9/L", "data_class": "MODELED", "basis": "Exercises SIR periprocedural threshold guardrail."}, {"name": "inr", "kind": "normal", "mean": 1.0, "sd": 0.15, "min": 0.9, "max": 1.8, "unit": "ratio", "data_class": "MODELED", "basis": "Exercises SIR arterial-access INR guardrail."}, {"name": "hemoglobin", "kind": "normal", "mean": 10.5, "sd": 1.8, "min": 6, "max": 15, "unit": "g/dL", "data_class": "MODELED", "basis": "Menorrhagia-related anemia is common; chart realism."}, {"name": "on_anticoagulant", "kind": "bernoulli", "p": 0.05, "data_class": "MODELED", "basis": "Triggers a pre-op hold/bridge decision in the EMR."}]$gv$::jsonb, $gg$[{"if": "creatinine>=1.5", "then": ["tag:CKD", "compute:egfr_ckd_epi_2021", "limit:contrast=min(cigarroa_vmax,acr_egfr_tier)"], "source": "game_config.contrast_vmax_formula (Cigarroa 1989) + egfr_contrast_tiers (ACR)"}, {"if": "platelets<20", "then": ["block:proceed", "order:platelet_transfusion"], "source": "SIR 2019 periprocedural thresholds"}, {"if": "platelets<50", "then": ["warn:arterial_access_hemostasis"], "source": "SIR 2019 (arterial access preferred >=50k)"}, {"if": "inr>1.8", "then": ["warn:correct_inr"], "source": "SIR 2019 arterial-access INR threshold"}, {"if": "on_anticoagulant==true", "then": ["flag:hold_bridge_decision"], "source": "SIR 2019: periprocedural anticoagulation management"}]$gg$::jsonb, 'published');

insert into public.procedure_game_params
 (procedure_id, vessel_map_id, access_node, target_node, pacing, emergent_decay,
  fluoro_target_min, fluoro_citation, base_payout, complexity, required_devices, case_steps)
values
 ('uterine-fibroid-embolization', 'femoral-to-uterine', 'cfa_access', 'uterine_target', 'stable', '{}'::jsonb,
  15.0, $fc$"MODELED placeholder (UFE is a longer-fluoro case); replace with a cited institutional/national DRL for UFE (Ryan)."$fc$::text, 2400, 4, $rd$["needle", "sheath", "catheter", "guidewire", "microcatheter", "particle", "closure"]$rd$::jsonb, $cs$[{"n": 1, "title": "Time-out & planning", "node": "cfa_access", "best": "timeout", "prompt": "Symptomatic fibroids, MRI reviewed. Begin the case.", "teaching": "Confirm symptomatic fibroids, patent uterine ostia, and no dominant ovarian supply before starting.", "outcomes": {"timeout": {"label": "Pre-procedure time-out; confirm MRI, symptoms, consent", "note": "Correct", "ok": "MRI shows dominant fundal fibroids with patent uterine arteries. Consent confirmed."}}, "default": {"score": [{"cat": "technical", "delta": -3, "reason": "Skipped the pre-procedure time-out."}], "narrative": "You skip the checklist and press on."}}, {"n": 2, "title": "Femoral access", "node": "cfa_access", "best": "us-micropuncture", "prompt": "Obtain arterial access and place a working sheath.", "teaching": "Ultrasound-guided common femoral access lowers access-site complications.", "outcomes": {"us-micropuncture": {"label": "Ultrasound-guided common femoral access, 5F sheath", "note": "Standard of care", "needs": ["micropuncture-needle-21g", "vascular-sheath-5f"], "imaging": "us", "ok": "Single anterior-wall CFA puncture under ultrasound; 5F sheath placed."}, "landmark": {"label": "Landmark femoral stick without ultrasound", "note": "Off-standard", "needs": ["micropuncture-needle-21g", "vascular-sheath-5f"], "score": [{"cat": "technical", "delta": -3, "reason": "Femoral access without ultrasound guidance.", "cite": "US-guided access reduces access-site complications"}], "ok": "Access obtained by palpation; sheath placed."}}, "default": {"score": [{"cat": "technical", "delta": -4, "reason": "That does not obtain arterial access."}], "narrative": "That won't get you into the femoral artery."}}, {"n": 3, "title": "Pelvic arteriogram", "node": "aortic_bifurc", "best": "dsa", "prompt": "Map the uterine arteries before selecting.", "teaching": "A diagnostic pelvic run identifies the uterine origins and any ovarian collateral supply.", "outcomes": {"dsa": {"label": "Pelvic DSA through a flush catheter", "note": "Correct roadmap", "needs": ["pigtail-flush-5f", "bentson-035-145"], "imaging": "dsa", "contrastMl": 12, "ok": "Pelvic arteriogram maps both uterine arteries; no dominant ovarian supply."}, "fluoro": {"label": "A quick fluoro spot instead of a full run", "note": "Inadequate roadmap", "imaging": "fluoro", "score": [{"cat": "technical", "delta": -3, "reason": "No diagnostic pelvic arteriogram before selection."}], "ok": "You skip the full run and start poking around."}}, "default": {"score": [{"cat": "technical", "delta": -3, "reason": "No pelvic roadmap obtained."}], "narrative": "You proceed without mapping the anatomy."}}, {"n": 4, "title": "Select the uterine artery", "node": "contra_iia", "best": "reform", "prompt": "Catheterize the (contralateral) uterine artery.", "teaching": "A reverse-curve catheter reforms to select the sharply reflexed uterine origin up-and-over the bifurcation.", "outcomes": {"reform": {"label": "Reform a reverse-curve catheter into the uterine artery", "note": "Correct", "needs": ["sos-omni-5f", "stiff-glidewire-035"], "imaging": "fluoro", "ok": "Reverse curve reformed; up-and-over to the contralateral internal iliac, then into the uterine artery."}, "advance-cath": {"label": "Push a straight catheter at the origin", "note": "Wrong shape for this angle", "score": [{"cat": "technical", "delta": -3, "reason": "A straight catheter cannot hold the sharply reflexed uterine origin."}], "ok": "The straight catheter keeps prolapsing out \u2014 no stable selection."}}, "default": {"score": [{"cat": "technical", "delta": -3, "reason": "Off-protocol at uterine selection."}], "narrative": "That doesn't select the uterine artery."}}, {"n": 5, "title": "Superselect", "node": "uterine_origin", "best": "superselect", "prompt": "Position a microcatheter for embolization.", "teaching": "Advancing distal to the cervicovaginal branch protects nontarget bladder/vaginal territory.", "outcomes": {"superselect": {"label": "Microcatheter distal to the cervicovaginal branch", "note": "Correct \u2014 protects nontarget territory", "needs": ["microcatheter-27-150"], "imaging": "fluoro", "ok": "Microcatheter parked in the horizontal segment, beyond the cervicovaginal branch."}, "advance-micro": {"label": "Microcatheter only to the proximal uterine artery", "note": "Proximal \u2014 higher nontarget risk", "needs": ["microcatheter-27-150"], "imaging": "fluoro", "setFlag": "proximal_embo", "score": [{"cat": "technical", "delta": -2, "reason": "Proximal microcatheter position raises nontarget/ovarian collateral risk."}], "ok": "Microcatheter sits proximally, near the cervicovaginal origin."}}, "default": {"score": [{"cat": "technical", "delta": -3, "reason": "Off-protocol at superselection."}], "narrative": "That doesn't superselect the uterine artery."}}, {"n": 6, "title": "Embolize to near-stasis", "node": "uterine_target", "best": "particles", "prompt": "Devascularize the fibroids.", "teaching": "Calibrated spheres to a slow-flow, pruned-tree endpoint \u2014 stop before stasis to limit reflux.", "outcomes": {"particles": {"label": "Inject calibrated microspheres to a pruned-tree endpoint", "note": "Correct endpoint", "needs": ["microspheres-500-700"], "imaging": "fluoro", "contrastMl": 6, "complication": {"name": "Nontarget embolization (bladder, vagina, skin)", "mult": 1, "decline": {"sbpDrop": 2}}, "ok": "500\u2013700 \u00b5m spheres to a slow-flow, pruned-tree endpoint.", "hit": "A little reflux \u2014 some spheres reach the bladder/vaginal branches."}}, "default": {"score": [{"cat": "technical", "delta": -4, "reason": "That does not embolize the fibroid bed appropriately (e.g., a proximal coil leaves collateral supply)."}], "narrative": "That isn't the right way to devascularize the fibroids."}}, {"n": 7, "title": "Contralateral side", "node": "uterine_target", "best": "reform", "prompt": "Treat the other uterine artery.", "teaching": "Bilateral treatment is standard \u2014 unilateral UFE has high recurrence.", "outcomes": {"reform": {"label": "Select and embolize the opposite uterine artery to the same endpoint", "note": "Bilateral is standard", "imaging": "fluoro", "contrastMl": 6, "complication": {"name": "Ovarian insufficiency", "mult": 1, "decline": {}}, "ok": "Contralateral uterine artery selected and embolized to near-stasis; bilateral treatment complete.", "hit": "Diffuse embolization compromises some ovarian arterial supply."}, "single-side": {"label": "Treat only the accessed side; skip the contralateral artery", "note": "Undertreatment", "score": [{"cat": "technical", "delta": -5, "reason": "Unilateral UFE \u2014 high recurrence; both uterine arteries should be treated."}], "ok": "You stop after one side."}}, "default": {"score": [{"cat": "technical", "delta": -3, "reason": "Off-protocol before treating the second side."}], "narrative": "That doesn't address the contralateral uterine artery."}}, {"n": 8, "title": "Completion & closure", "node": "cfa_access", "best": "closure-device", "prompt": "Finish the case.", "teaching": "A completion run documents bilateral devascularization; both closure devices and manual pressure are acceptable.", "outcomes": {"closure-device": {"label": "Completion pelvic run, then a closure device", "note": "Correct", "needs": ["collagen-plug-closure"], "imaging": "dsa", "contrastMl": 5, "ok": "Completion run confirms bilateral devascularization; collagen-plug closure with good hemostasis. Expect post-embolization syndrome (cramping, low-grade fever) \u2014 managed with NSAIDs/anti-emetics on the ward."}, "manual-closure": {"label": "Completion run, then hold manual pressure", "note": "Also acceptable", "imaging": "dsa", "contrastMl": 5, "ok": "Completion run good; ~15 minutes of manual pressure to hemostasis."}}, "default": {"score": [{"cat": "technical", "delta": -4, "reason": "Closed without a completion angiogram."}], "narrative": "You close without documenting the result."}}]$cs$::jsonb)
on conflict (procedure_id) do update set
  vessel_map_id=excluded.vessel_map_id, access_node=excluded.access_node, target_node=excluded.target_node,
  pacing=excluded.pacing, fluoro_target_min=excluded.fluoro_target_min, fluoro_citation=excluded.fluoro_citation,
  base_payout=excluded.base_payout, complexity=excluded.complexity, required_devices=excluded.required_devices,
  case_steps=excluded.case_steps;

update public.game_config
   set value = jsonb_set(value, '{required_kit,uterine-fibroid-embolization}', $kit$["micropuncture-needle-21g", "vascular-sheath-5f", "bentson-035-145", "stiff-glidewire-035", "pigtail-flush-5f", "sos-omni-5f", "microcatheter-27-150", "microspheres-500-700", "collagen-plug-closure"]$kit$::jsonb, true)
 where key = 'economy';
